from pycryptodome import AES, CBC
import base64
import hashlib
import os

def get_key():
    config_file = "config.txt"
    with open(config_file, 'r') as f:
        key = f.read().strip()
    return hashlib.sha256(key.encode()).digest()

def encrypt(credit_card_number):
    key = get_key()
    iv = b'0' * AES.block_size
    cipher = AES.new(key, AES.MODE_CBC, iv)
    encrypted_data = base64.b64encode(iv + cipher.encrypt(credit_card_number))
    return encrypted_data

def decrypt(encrypted_data):
    key = get_key()
    encrypted_data = base64.b64decode(encrypted_data)
    iv = encrypted_data[:AES.block_size]
    cipher = AES.new(key, AES.MODE_CBC, iv)
    return cipher.decrypt(encrypted_data[AES.block_size:])